import emailValidator from "email-validator";

export function validateEmailOffline(email) {
  const trimmed = String(email || "").trim();
  if (!trimmed) return { email: trimmed, isValid: false, reason: "Email is required", creditCost: 0 };
  const isValid = emailValidator.validate(trimmed);
  return {
    email: trimmed,
    isValid,
    reason: isValid ? "Valid format (offline mode)" : "Invalid email format",
    creditCost: 0,
  };
}
